import sys
sys.setrecursionlimit(1 << 25)

def solve(c: int, connections: list[list[int]], queries: list[list[int]]) -> list[int]:
    from collections import defaultdict

    # Build the graph
    graph = defaultdict(list)
    for u, v in connections:
        graph[u].append(v)
        graph[v].append(u)

    # Union-Find (Disjoint Set Union) data structure
    parent = list(range(c + 1))  # 1-based indexing
    rank = [1] * (c + 1)

    def find(u):
        while parent[u] != u:
            parent[u] = parent[parent[u]]  # Path compression
            u = parent[u]
        return u

    def union(u, v):
        u_root = find(u)
        v_root = find(v)
        if u_root == v_root:
            return
        # Union by rank
        if rank[u_root] < rank[v_root]:
            parent[u_root] = v_root
        else:
            parent[v_root] = u_root
            if rank[u_root] == rank[v_root]:
                rank[u_root] += 1

    # Build the DSU based on the connections
    for u, v in connections:
        union(u, v)

    # For each component, keep track of the minimum id
    component_min = [0] * (c + 1)
    for i in range(1, c + 1):
        component_min[find(i)] = i

    # Track which nodes are online
    online = [True] * (c + 1)

    result = []

    for query in queries:
        if query[0] == 1:
            x = query[1]
            if online[x]:
                result.append(x)
                online[x] = False
            else:
                root = find(x)
                min_id = component_min[root]
                if online[min_id]:
                    result.append(min_id)
                else:
                    result.append(-1)
        else:
            x = query[1]
            online[x] = False

    return result
